define i1 @ult_2(i32 %x) {
  %t = trunc i32 %x to i8
  %r = icmp ult i8 %t, 2
  ret i1 %r
}

define i1 @do_not_mask_trunc_eq_i32_i8(i32 %x) {
  %t = trunc nuw i32 %x to i8
  %r = icmp eq i8 %t, 42
  ret i1 %r
}

define <2 x i1> @uge_nsw_non_splat(<2 x i32> %x) {
  %t = trunc nsw <2 x i32> %x to <2 x i8>
  %r = icmp uge <2 x i8> %t, <i8 45, i8 46>
  ret <2 x i1> %r
}
